insert into aulas (id, modulo_id, titulo, descricao, video_url, duracao_seg, ordem, tipo) values
  ('715483cf-b387-47c0-995b-4b00faa196cd', '261507eb-6739-4e23-a326-e2cdab659860', 'Por essa você não esperava!', 'Baixe a apostila e os arquivos complementares para acompanhar o curso adequadamente!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=0e5b57e0-f5d5-4e89-b508-a342eb39f3da', 0, 0, 'aula'),
  ('a7128ea2-47d1-4f53-8c83-aeeeb9e203e7', '261507eb-6739-4e23-a326-e2cdab659860', 'Estrutura do Poder Judiciário', 'Como funciona o poder judicário e onde são julgados os processos.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=ffe3b903-83d2-452f-aafa-b6a4c2abdd95', 0, 1, 'aula'),
  ('2b4e00db-a905-4ded-a81f-4ea486cbad2d', '261507eb-6739-4e23-a326-e2cdab659860', 'Noções Processuais e Vocabulário Jurídico', 'Nesta aula vamos entender um pouco sobre os principais temas dos documentos judiciais, bem como seu entendimento.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=82e2f08a-b10a-4005-8d45-c1e35217f574', 0, 2, 'aula'),
  ('07f3e567-6bae-4f69-b52d-f9527747e5d1', 'e3950207-1636-49de-860c-fcc6b115334c', 'Caminhos e Técnicas para Interpretação Processual', 'Interpretação judicial é técnica e experiência, conheça algumas dicas que vão facilitar seu caminho.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=e5f90bd4-de6f-4a2b-916e-3781573b536f', 0, 0, 'aula'),
  ('5fbadd76-6cd8-43cc-a9e0-17eb806ccabf', 'e3950207-1636-49de-860c-fcc6b115334c', 'Passos para elaboração e apresentação dos cálculos judiciais', 'Cálculo judicial é uma arte e deve ser elaborado com organização e ordem.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=acbd97db-be66-4d21-a639-1cac737e1e3b', 0, 1, 'aula'),
  ('638251ba-4d61-4ea8-9def-5cc36237c6c3', 'e3950207-1636-49de-860c-fcc6b115334c', 'Resumo e Ordem de Apresentação dos Cálculos', 'Nesta aula veremos qual a ordem correta da apresentação das peças dos cálculos e bem como as informações que devem sempre constar no resumo de nossos números.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=ef140298-71d6-4d9f-ac29-f573ab7c4c06', 0, 2, 'aula'),
  ('71a93a0d-846e-48f7-a803-ee2d8e5a07da', 'd4823385-a44b-465a-a263-7e9fb48c7db7', '(Exemplo 01) Leitura, Interpretação e Montagem de Síntese Processual', 'Como elaborar uma síntese processual perfeita através da leitura e interpretação do processo.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=33b806b4-51e2-4a81-a5bc-cd286dedbcce', 0, 0, 'aula'),
  ('a88e5850-d3e1-45bb-bd2b-f4c8ca45f596', 'd4823385-a44b-465a-a263-7e9fb48c7db7', '(Exemplo 02) Leitura, Interpretação e Montagem de Síntese Processual', 'Leitura integral de uma decisão, para compreende como funcionar a escrita jurídica, bem como a ordem lógica da apresentação.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=cd72deca-256b-46b5-842b-a8290b1ee656', 0, 1, 'aula'),
  ('5004223c-b279-44aa-adb8-5fcb97c6beba', '837f4ede-93c7-4334-8b33-846e5e848fdd', 'Resolução da prova final', 'Veja o arquivo em anexo como eu fiz a minha síntese processual desta prova.', null, 0, 0, 'material'),
  ('ca16c43c-cb26-4257-92dd-0195bbaf54b5', '837f4ede-93c7-4334-8b33-846e5e848fdd', 'Encerramento e reflexão da importância do curso', 'Que tal?!!?

Parabéns por ter concluído com êxito essa etapa tão importante dos cálculos... sem ela não iremos a lugar nenhum, ou melhor, iremos para o "buraco". Tenha sempre a convicção de que a leitura é fundamental para os cálculos e deve ser feita com muita atenção e zelo.

Agora que você já conseguiu a nota mínima (que não é pouca) para passar pela prova final, disponibilizo a você meu arquivo de síntese para ter uma ideia de como deve ser seu trabalho de reunir todas as informações processuais em um único documento, de forma segura e confiável!

Parabéns e vamos em frente!

Antes de completar esta aula

Estou compartilhando um link onde deixei vários processos de diferentes discussões para que você possa treinar ainda mais tua habilidade de interpretar e ler um processo judicial.

https://drive.google.com/drive/folders/1Uva6eO4itKGNVqVrb5sMMaAyZopof7OE?usp=sharing

Acredito que você!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=733d26ed-6cc9-46c9-9294-48006fcd048c', 0, 1, 'aula'),
  ('138deb68-676b-4e19-a428-9347fd7b8b39', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Aprendendo sobre formatos numéricos', 'Nessa aula você entenderá os formatos numéricos que o Excel disponibiliza, compreendendo diferenças importantes entre os formatos Moeda e Contábil, bem como, as variações do formato Número e a utilidade do formato Geral.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=c4a0ad6a-6794-4869-ac9c-33c702d7336f', 0, 0, 'aula'),
  ('284dcf76-d2a9-4ea0-9491-5c4ec68b15b3', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Formatos de data e hora', 'Nessa aula vamos falar sobre os formatos de Data e Hora, vamos entender sobre como o Excel interpreta Datas e como você pode lidar com problema nos cálculos com hora.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=01f393b2-5c91-4114-82d5-6e5a578f4fe5', 0, 1, 'aula'),
  ('d3394d2b-9bca-4e55-830a-d40269b783cf', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Formato de Porcentagem', 'Nessa aula falaremos sobre o formato porcentagem e aprenderemos como tratar o problema da conversão decimal para porcentagem.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=b4026c58-8e42-4c84-b2e6-780ab22a11e5', 0, 2, 'aula'),
  ('f8951667-d475-46f1-9d30-6dfde24484c3', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Formatos Fração e Científico', 'Os formatos fração e científico são pouco utilizados do dia-a-dia, mas é importante você saber lidar com eles para corrigir problemas futuros, veremos isso nessa aula.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=277cfc57-7997-42c5-839d-fb232e36b24e', 0, 3, 'aula'),
  ('d0601b8f-c818-4a52-a18d-7c6ce26b8322', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Formatos Especiais', 'Nessa aula veremos modelos úteis e inúteis do formato especial.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=936ed8ce-5a12-44b4-9c0e-bba7a00f3071', 0, 4, 'aula'),
  ('355cea52-c8e2-4b8c-a9c7-54404d448e01', '4e32a45e-4d66-4cf5-8465-5d1fde4c0614', 'Criar Formatos Personalizados', 'Nessa aula conheceremos as possibilidades de formatos personalizados do Excel. Você perceberá que podemos facilmente criar formatos personalizados respeitando as máscaras necessárias.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=b5f53bd6-27cf-4aa1-9ffa-46c1311df41c', 0, 5, 'aula'),
  ('9727732f-145d-44b9-bd3e-f21ae34ce634', 'a6c08330-1146-4b72-a71e-9f7410d2d282', 'Operadores Aritméticos', 'Nesta aula você aprenderá a realizar cálculos no Excel. Falaremos sobre a ordem dos operadores, bem como, cálculos com porcentagem.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=f3828953-4e03-4288-b5dc-740743cd8dca', 0, 0, 'aula'),
  ('25c4874a-8d2b-447c-be7f-679c1d4c764d', 'a6c08330-1146-4b72-a71e-9f7410d2d282', 'Operador de Texto', 'Nessa aula você vai aprender a lidar com o operador de texto.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=1cc981c8-b0bf-4c8b-825c-b7dde1362815', 0, 1, 'aula'),
  ('1c3268f9-6418-4111-8f1f-9f98af4dfee7', 'a6c08330-1146-4b72-a71e-9f7410d2d282', 'Operadores de Comparação', 'Entender sobre o uso desses operadores é muito importante para as aulas sobre funções de lógica. Aprenderemos a fazer perguntas ao Excel.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=ae3fcb89-31cf-46cc-9c77-c187f0912599', 0, 2, 'aula'),
  ('f6558ce1-1221-45ba-8b9d-0c164e5a8fb0', 'a6c08330-1146-4b72-a71e-9f7410d2d282', 'Operadores de Referência', 'Nessa aula falaremos sobre a importância dos operadores de referência na construções de funções.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=c6bee181-803a-4c1e-818c-5403d7476d52', 0, 3, 'aula'),
  ('82504b94-59ff-41a8-b735-c30abbfda824', 'ab46c3b9-49d5-4e03-a5ac-a2ec98f2a67d', 'Conhecendo Função', 'Antes de falarmos sobre funções em um nível mais avançado precisamos entender as lógicas e etapas na criação de funções e é isso que veremos nessa aula.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=c727154e-911b-4e29-bff5-2022bf0fab75', 0, 0, 'aula'),
  ('cb1de1eb-9c48-42f2-9830-d36c938908b1', 'ab46c3b9-49d5-4e03-a5ac-a2ec98f2a67d', 'Funções Básicas', 'Vamos aos primeiros passos com funções! Nessa aula veremos funções básicas e a forma de trabalhar com diferentes intervalos.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=edd2b477-3a29-4aa4-9115-175382bca51e', 0, 1, 'aula'),
  ('66844628-5c0c-4068-884d-c8530c9c9cff', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Conhecendo as Funções de Data mais Importantes', 'Agora que você já começou a trabalhar com funções vamos avançar! Nessa aula veremos as principais funções de Data e também como trabalhar com mais de um parâmetro nas funções.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=0321d336-1a94-415c-9057-bd376647daac', 0, 0, 'aula'),
  ('6397b5a7-5bc4-44bb-a639-dd606b548a27', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Conhecendo e Exercitando Funções de Texto', 'Chegamos as funções de Texto! Trabalhar com função de Texto pode ser um bom quebra cabeças, ótimo para construção de raciocínio lógico.

Não perca e não deixe de fazer os exercícios!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=2ed17312-0c2a-40b7-8553-fba8f866171b', 0, 1, 'aula'),
  ('432320e5-195f-486c-9625-3d8b0b467ff1', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Primeiro contato com função SE', 'Chegamos a aula da principal função de lógica do Excel! Nessa aula vamos falar de função SE, você vai aprender a trabalhar com lógica no Excel... Lembro que esse é apenas o primeiro passo, teremos mais duas aulas com essa função e mais uma com a função SES.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=cc7ee488-2c77-439e-b112-04c19499bd5b', 0, 2, 'aula'),
  ('46127a04-8fdd-4b4d-b28f-bdd4a5ea98ff', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Função SE com duas ou mais condicionais', 'Muito bem! Nessa aula vamos falar de função SE em um cenário mais avançado. Vamos aprender a trabalhar com essa função de forma agregada, aprendendo a trabalhar com mais de uma função SE ao mesmo tempo.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=7028cd34-d2f2-4fe1-a9c0-7088402c1aa9', 0, 3, 'aula'),
  ('67d702eb-bedf-4990-a864-7bea3a274a26', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Função SE com E e OU', 'Agora chegamos ao cenário mais avançado! Você vai aprender a usar as funções E e OU junto com a função SE e isso abrirá muitas possibilidades de aplicação no seu dia-a-dia.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=e7fecbc9-5c17-435f-976d-cd2f3398e784', 0, 4, 'aula'),
  ('8caeab0e-713f-4c46-8faf-8a8922194bf8', 'ecadba4f-abb5-4558-9352-192edd748d2a', 'Conhecendo a Função SES', 'A função SES foi criada na versão 2013 do Excel e veio para facilitar os trabalhos com função SE agregada.

O exemplo aplicado nesta aula mostra como isso acontece.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=95bf3f8f-37b1-42a0-9fbf-91b8026baf95', 0, 5, 'aula'),
  ('f5af705b-5c66-4a1b-a837-896e6d070ab3', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Funções CONT.SES e SOMASES', 'Essa aula é um pouco mais longa... Mas não deixe de assistir! Fique muito atento, as funções CONT.SES e SOMASES são muito importantes no nosso aprendizado! Além das funções, nessa aula você aprenderá a usar cifrão nas funções, para "congelar" os parâmetros.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=b5cbdf05-d684-4620-acba-8a85a594cf14', 0, 0, 'aula'),
  ('fb856240-d355-4ebb-b629-6b87830a1bbf', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Entendendo PROCV', 'Chegamos a função mais esperada nos treinamentos! A Função PROCV é sim, muito útil e vamos ver isso nessa aula... Não perca!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=1c11bab2-ebca-4f56-afea-03b597c6ce57', 0, 1, 'aula'),
  ('fde991d5-43d6-4e0f-a3f5-febe86cc7c1f', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Como usar PROCH e PROCH com CORRESP', 'Ta aí uma boa combinação! Nessa aula você vai conhecer a função PROCH e perceber que podemos resolver grandes problemas combinando-a com a função CORRESP.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=7fc6998b-9ab0-4e99-905b-9d304c3f997e', 0, 2, 'aula'),
  ('e8b3905f-0d19-4ae5-a656-1091be307ec2', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Por que usar ÍNDICE com CORRESP', 'Chegamos a combinação perfeita! Muitas pessoas deixam de usar PROCV para trabalhar com essa combinação de funções.

Nessa aula você vai entender o porque e quando utilizar essa combinação de funções.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=2489a382-230c-40b5-bd86-e49946283baa', 0, 3, 'aula'),
  ('25b81361-d0f7-4d75-8559-27f7ae13f312', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Conhecendo a novidade, PROCX', 'Chegou a novidade! A função PROCX veio para revolucionar!

Não perca essa aula e fique por dentro das novidades do Excel.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=6b07dba2-2a1c-4d76-bb5c-d28d242a1d9c', 0, 4, 'aula'),
  ('35e47628-e667-4fda-be71-f528bd464665', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Aprendendo a usar a Função DESLOC', '', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=0b7de84f-52b9-486f-b120-ff504bb604e8', 0, 5, 'aula'),
  ('4447e52c-8ed3-4c35-b27d-c6673e846570', '5ad29dd5-8922-41f9-b171-84882a5bda20', 'Conhecendo a Função INDIRETO', 'Chegamos a última aula deste Módulo. A função Indireto é muito interessante para resolver problemas de intervalos variáveis e nessa aula você vai entender muito bem isso!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=2b01fb7d-1d50-4c59-af8d-c1bc2f5021cb', 0, 6, 'aula'),
  ('f7563ece-db44-4139-be18-95e82bd6ecc7', '0c4220d6-2432-4b9c-859f-1b4bdb8924b8', 'Classificação e Filtro', 'As ferramentas Classificar e Filtro são de nível iniciante, porém muito importantes! Caso utilize pouco essas ferramentas ou tenha dúvidas de como funcionam, não perca essa aula.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=ae74ac68-08e4-4df9-8387-122297c4d6c3', 0, 0, 'aula'),
  ('d40c86e2-d23f-4b26-990a-c94ada706cd0', '0c4220d6-2432-4b9c-859f-1b4bdb8924b8', 'Congelar Painéis', 'A ferramenta Congelar Painéis é muito útil no uso de relatório extensos, no qual cabeçalhos saem da tela ao rolar para baixo, mas é importante que você saiba que essa ferramenta vai além disso! É o que vamos ver nessa aula...', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=33ea2d0e-8232-422f-bce3-11a847181ce0', 0, 1, 'aula'),
  ('6c7cbc9c-be09-4485-95ed-6c459b28eabc', '0c4220d6-2432-4b9c-859f-1b4bdb8924b8', 'Agrupadores', 'Essa ferramenta pode ser utilizada para substituir o hábito que algumas pessoas tem de ocultar linhas e colunas. Veja como fazer isso!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=9bd77a1d-b006-4755-8106-60f99d50c4eb', 0, 2, 'aula'),
  ('a66180b4-2112-4c32-a862-a7027cf5dec8', '0c4220d6-2432-4b9c-859f-1b4bdb8924b8', 'Conhecendo a ferramenta Tabela', 'Ferramenta muito interessante e pouco utilizada... Veja o que podemos fazer com essa ferramenta.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=de74ecf9-889d-4d68-8337-93fbeba97523', 0, 3, 'aula'),
  ('8a58eee3-908a-454f-8cb4-22322cf5e2fa', '634b06e3-fb07-480f-8969-3f8fa8c6e6bc', 'Conhecendo Tabela Dinâmica', 'Chegamos a principal ferramenta do Excel!! Nessa aula você aprenderá a criar tabelas dinâmicas, entendendo como funciona cada campo e o melhor que podemos extrair de cada um deles.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=bce77ee9-63a6-444a-a1f4-fd516469bada', 0, 0, 'aula'),
  ('789a172f-c016-442c-b71d-1d9a35a4a99a', '634b06e3-fb07-480f-8969-3f8fa8c6e6bc', 'Criando Campo Calculado', 'O assunto fica mais avançado agora! Você vai aprender a criar colunas utilizando cálculos e funções diretamente na Tabela Dinâmica, isso tornará seu trabalho mais eficiente. Não perca essa aula!', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=8fa2487e-3653-4d54-82fa-5393877b3904', 0, 1, 'aula'),
  ('ae9d0ee2-17e1-4128-8ccd-2d9f277ffc3a', '634b06e3-fb07-480f-8969-3f8fa8c6e6bc', 'Dominando Segmentação de Dados', 'Essa ferramenta foi a grande evolução da Tabela Dinâmica! Segmentação de Tabela dinâmica é muito interessante e irá mudar a cara dos seus relatórios e dashboard.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=6ca68769-4ae0-4e61-bd02-b02a9a020e16', 0, 2, 'aula'),
